Usage:
# register in default section
@profile.register_check
@check(id='com.example.openbakery/check/0')
def my_check():
  yield PASS, 'example'

# register in `special_section` also register that section in the profile
@profile.register_check(special_section)
@check(id='com.example.openbakery/check/0')
def my_check():
  yield PASS, 'example'

